import{_ as i,o as t,c as o,ag as a}from"./chunks/framework.DXGyWiRo.js";const g=JSON.parse('{"title":"Drone Encrypted Flight Logs (Yuneec ST-16)","description":"Imported note from https://jamiesharpe.co.uk/2024/11/19/drones-encrypted-flight-logs/","frontmatter":{"title":"Drone Encrypted Flight Logs (Yuneec ST-16)","description":"Imported note from https://jamiesharpe.co.uk/2024/11/19/drones-encrypted-flight-logs/"},"headers":[],"relativePath":"pen-testing/drones/jamie-sharpe-drones-encrypted-flight-logs.md","filePath":"pen-testing/drones/jamie-sharpe-drones-encrypted-flight-logs.md"}'),r={name:"pen-testing/drones/jamie-sharpe-drones-encrypted-flight-logs.md"};function l(n,e,s,c,d,p){return t(),o("div",null,[...e[0]||(e[0]=[a('<h1 id="drone-encrypted-flight-logs-yuneec-st-16" tabindex="-1">Drone Encrypted Flight Logs (Yuneec ST-16) <a class="header-anchor" href="#drone-encrypted-flight-logs-yuneec-st-16" aria-label="Permalink to &quot;Drone Encrypted Flight Logs (Yuneec ST-16)&quot;">​</a></h1><h2 id="source" tabindex="-1">Source <a class="header-anchor" href="#source" aria-label="Permalink to &quot;Source&quot;">​</a></h2><ul><li>Type: webpage</li><li>Origin: <a href="https://jamiesharpe.co.uk/2024/11/19/drones-encrypted-flight-logs/" target="_blank" rel="noreferrer">https://jamiesharpe.co.uk/2024/11/19/drones-encrypted-flight-logs/</a></li><li>Imported: 2026-04-21</li></ul><h2 id="content" tabindex="-1">Content <a class="header-anchor" href="#content" aria-label="Permalink to &quot;Content&quot;">​</a></h2><p>This post documents a practical reverse-engineering workflow for decrypting Yuneec ST-16 drone flight logs by recovering a static key from decompiled Android APKs.</p><h3 id="scope-and-prerequisites" tabindex="-1">Scope and prerequisites <a class="header-anchor" href="#scope-and-prerequisites" aria-label="Permalink to &quot;Scope and prerequisites&quot;">​</a></h3><ul><li>Intended for digital investigations involving drone controllers.</li><li>Requires baseline familiarity with Android/mobile forensics and reverse engineering.</li><li>Suggested tooling: <ul><li>APK decompiler (<code>jadx</code>)</li><li>Hex editor (for byte-level comparison)</li><li>Sample plaintext and encrypted flight logs</li></ul></li></ul><h3 id="flight-log-locations" tabindex="-1">Flight log locations <a class="header-anchor" href="#flight-log-locations" aria-label="Permalink to &quot;Flight log locations&quot;">​</a></h3><p>The post identifies two key directories on the controller:</p><ul><li><code>/root/media/0/FlightEncryptLog</code> (encrypted logs)</li><li><code>/root/media/0/FlightLog</code> (plaintext logs)</li></ul><p>It notes that encrypted logs can remain even when plaintext counterparts are deleted, which may be useful for recovery in investigations.</p><h3 id="reverse-engineering-approach" tabindex="-1">Reverse engineering approach <a class="header-anchor" href="#reverse-engineering-approach" aria-label="Permalink to &quot;Reverse engineering approach&quot;">​</a></h3><ol><li>Decompile relevant Yuneec APKs (<code>FlightMode.apk</code>, <code>droneFly.apk</code>, or <code>Yuneec-App-Release.apk</code>).</li><li>Search code for references such as <code>FlightEncryptLog</code>.</li><li>Locate crypto implementation in a <code>DES</code> class.</li><li>Extract static key material and cipher settings.</li></ol><p>Key value observed:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>ksYuN2eC</span></span></code></pre></div><p>Cipher configuration described:</p><ul><li>Algorithm/mode/padding: <code>DES/CBC/PKCS5Padding</code></li><li>Key: UTF-8 bytes of <code>ksYuN2eC</code></li><li>IV: UTF-8 bytes of <code>ksYuN2eC</code></li></ul><h3 id="validation-workflow" tabindex="-1">Validation workflow <a class="header-anchor" href="#validation-workflow" aria-label="Permalink to &quot;Validation workflow&quot;">​</a></h3><ul><li>Use a known plaintext segment (for example CSV headers common to flight logs).</li><li>Re-encrypt with the recovered DES parameters.</li><li>Compare resulting ciphertext bytes with encrypted log bytes in hex view.</li><li>The post highlights near-match behavior with expected differences at padded tail bytes.</li></ul><h3 id="automation-output" tabindex="-1">Automation output <a class="header-anchor" href="#automation-output" aria-label="Permalink to &quot;Automation output&quot;">​</a></h3><ul><li>Author provides a bulk decryption utility: <ul><li>Repository: <a href="https://github.com/JamieSharpe/DroneFlightLogDecryptor" target="_blank" rel="noreferrer">DroneFlightLogDecryptor</a></li><li>Purpose: batch decrypt flight log files for examiner workflows</li></ul></li></ul><h3 id="investigation-value" tabindex="-1">Investigation value <a class="header-anchor" href="#investigation-value" aria-label="Permalink to &quot;Investigation value&quot;">​</a></h3><ul><li>Demonstrates how static-key client-side crypto can be recovered from app binaries.</li><li>Provides a repeatable method from acquisition through key discovery to decryption validation.</li><li>Emphasizes practical examiner use where only encrypted logs are available.</li></ul><h2 id="key-takeaways" tabindex="-1">Key Takeaways <a class="header-anchor" href="#key-takeaways" aria-label="Permalink to &quot;Key Takeaways&quot;">​</a></h2><ul><li>Decompiled mobile app code can expose hardcoded keys and decryption routines.</li><li>Yuneec ST-16 flight logs are described as decryptable using recovered DES-CBC parameters.</li><li>Encrypted logs may persist even when plaintext logs are removed, creating forensic opportunities.</li><li>Reproducible decryption at scale is feasible with scripting or dedicated tooling.</li></ul>',25)])])}const u=i(r,[["render",l]]);export{g as __pageData,u as default};
